item.command:
$dirs_to_copy = @(
  "vikunja", "vikunja_mcp", "fleet_ops", "fleet_observability",
  "autonomy_budget", "gate_stale_cleaner", "scheduled-tasks"
);
foreach ($d in $dirs_to_copy) {
  Copy-Item -Recurse -Force "C:\Users\mrbla\BlarAI\tools\$d" "C:\Users\mrbla\devplatform\tools\$d"
}
# Also copy the shared helpers created in Stage 2
Copy-Item "C:\Users\mrbla\BlarAI\tools\_vikunja_client.py" "C:\Users\mrbla\devplatform\tools\_vikunja_client.py"
Copy-Item "C:\Users\mrbla\BlarAI\tools\_project_context.py" "C:\Users\mrbla\devplatform\tools\_project_context.py"

$patterns = @("CLAUDE_*.md","CLAUDE_*.xml","CO_LEAD_*.xml","DEC*.xml","DOMAIN*.xml");
foreach ($p in $patterns) {
  Get-ChildItem C:\Users\mrbla\BlarAI\docs\$p -File -ErrorAction SilentlyContinue |
    Copy-Item -Destination C:\Users\mrbla\devplatform\docs\
}

if ((Get-ChildItem C:\Users\mrbla\BlarAI\claude_cowork -ErrorAction SilentlyContinue).Count -gt 0) {
  Copy-Item -Recurse C:\Users\mrbla\BlarAI\claude_cowork C:\Users\mrbla\devplatform\
}
if ((Get-ChildItem C:\Users\mrbla\BlarAI\claude_projects -ErrorAction SilentlyContinue).Count -gt 0) {
  Copy-Item -Recurse C:\Users\mrbla\BlarAI\claude_projects C:\Users\mrbla\devplatform\
}
